+package swarm
+
+import (
+	"context"
+	"sync"
+	"testing"
+	"time"
+
+	"github.com/Dicklesworthstone/ntm/internal/tmux"
+)
+
+// mockPaneSpawner implements context.PaneSpawner for testing.
+type mockPaneSpawner struct {
+	mu           sync.Mutex
+	spawnCalls   []spawnCall
+	killCalls    []string
+	sendKeysCalls []sendKeysCall
+	spawnErr     error
+	killErr      error
+	sendKeysErr  error
+	panes        []tmux.Pane
+}
+
+type spawnCall struct {
+	session   string
+	agentType string
+	index     int
+	variant   string
+	workDir   string
+}
+
+type sendKeysCall struct {
+	paneID string
+	text   string
+	enter  bool
+}
+
+func (m *mockPaneSpawner) SpawnAgent(session, agentType string, index int, variant string, workDir string) (string, error) {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	m.spawnCalls = append(m.spawnCalls, spawnCall{
+		session:   session,
+		agentType: agentType,
+		index:     index,
+		variant:   variant,
+		workDir:   workDir,
+	})
+	if m.spawnErr != nil {
+		return "", m.spawnErr
+	}
+	return session + ":1.1", nil
+}
+
+func (m *mockPaneSpawner) KillPane(paneID string) error {
