+		AgentType:   "cc",
+	}
+
+	// Fill the channel
+	r.emitEvent(result)
+
+	// This should not block (non-blocking send)
+	done := make(chan bool)
+	go func() {
+		r.emitEvent(result) // This would block if not non-blocking
+		done <- true
+	}()
+
+	select {
+	case <-done:
